import{_ as e,o as r,c as a,a2 as o}from"./chunks/framework.CY0RMtsF.js";const d="/mug-typography-docs/image/inspector_character_settings.webp",n="/mug-typography-docs/image/align-h.webp",s="/mug-typography-docs/image/align-v.webp",u=JSON.parse('{"title":"文字個別設定 (Character Settings)","description":"","frontmatter":{"title":"文字個別設定 (Character Settings)"},"headers":[],"relativePath":"reference/reference-character-settings.md","filePath":"reference/reference-character-settings.md"}'),l={name:"reference/reference-character-settings.md"};function i(c,t,h,g,b,p){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="page-character-settings" tabindex="-1">Page: Character Settings <a class="header-anchor" href="#page-character-settings" aria-label="Permalink to &quot;Page: Character Settings&quot;">​</a></h1><p>キャラクター選択モード（Character）で選択した文字に対して個別の変形を設定するページです。 パラメーターのスロット数は、選択しているプリセット（Low / Mid / High）や <code>preferences.json</code> の設定によって異なります（詳細は付録の「<a href="#limitations-ja">制限事項</a>」を参照）。</p><p>キャラクターへの変形は、<strong>グローバル変形に追加で適用</strong>されます。</p><p><img src="'+d+'" alt="Character Settings"></p><h2 id="文字の整列-align-selected" tabindex="-1">文字の整列（Align Selected） <a class="header-anchor" href="#文字の整列-align-selected" aria-label="Permalink to &quot;文字の整列（Align Selected）&quot;">​</a></h2><p>ビューア上で複数選択した文字を、文字のスケールを考慮してきれいに並べ直すためのボタンです。インスペクタページの上部に配置されています。</p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p><strong>選択モードの制限について</strong><br> 文字の整列機能は、ビューア上での<strong>文字選択モード（Character）が有効な場合のみ機能します。</strong> グローバル（Global）およびパーツ（Part）選択モードでは機能しませんのでご注意ください。</p></div><table tabindex="0"><thead><tr><th>パラメーター</th><th>説明</th><th>デフォルトショートカット</th></tr></thead><tbody><tr><td><strong>Align Selected Horizontally</strong></td><td>選択中の文字のうち、最も左にある文字の左端を基準として、他の文字を右方向へ隙間なく配置します。各文字のベースライン（垂直位置）が揃うように整列され、各文字のピボット（Pivot）はデフォルト（0.5, 0.5）にリセットされます。</td><td><code>Alt+Ctrl+H</code> <br>(Mac: <code>Option+Command+H</code>)</td></tr><tr><td><strong>Align Selected Vertically</strong></td><td>選択中の文字のうち、最も上にある文字の上端を基準として、他の文字を下方向へ隙間なく配置します。列の中心軸（水平位置）が揃うように整列され、各文字のピボット（Pivot）はデフォルト（0.5, 0.5）にリセットされます。</td><td><code>Alt+Ctrl+V</code> <br>(Mac: <code>Option+Command+V</code>)</td></tr></tbody></table><h4 id="整列-align-selected-サンプル" tabindex="-1">整列（Align Selected）サンプル <a class="header-anchor" href="#整列-align-selected-サンプル" aria-label="Permalink to &quot;整列（Align Selected）サンプル&quot;">​</a></h4><table tabindex="0"><thead><tr><th>整列方向</th><th>動作サンプル</th></tr></thead><tbody><tr><td><strong>水平整列 (Align Selected Horizontally)</strong></td><td><img src="'+n+'" alt="Align Horizontally"></td></tr><tr><td><strong>垂直整列 (Align Selected Vertically)</strong></td><td><img src="'+s+'" alt="Align Vertically"></td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p><strong>ショートカットキーに Alt+Ctrl を使用している理由</strong><br> 通常のショートカットキー（Alt+アルファベットなど）と異なり、<code>Alt+Ctrl</code> が割り当てられています。これは、DaVinci Resolve 自体が <code>Alt+V</code> を「属性の貼り付け (Paste Attributes)」などのホスト機能として優先消費してしまう仕様があり、プラグイン側でキー入力を確実にキャッチできるようにするための衝突回避策です。<br> ※ショートカットの割り当てキーは、設定ファイル <code>preferences.json</code> でカスタマイズ可能です。</p></div><h2 id="個々の文字の設定項目-character-1-2" tabindex="-1">個々の文字の設定項目（Character 1, 2...） <a class="header-anchor" href="#個々の文字の設定項目-character-1-2" aria-label="Permalink to &quot;個々の文字の設定項目（Character 1, 2...）&quot;">​</a></h2><p>「Character 1」などのグループを展開すると、選択した特定の文字に対する個別設定項目が表示されます。</p><h3 id="リセット-reset" tabindex="-1">リセット（Reset） <a class="header-anchor" href="#リセット-reset" aria-label="Permalink to &quot;リセット（Reset）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>パラメーター</th><th>説明</th></tr></thead><tbody><tr><td><strong>Reset This Character</strong></td><td>その文字と、その文字に属するすべてのパーツの Pos / Pivot / Scale / Stretch / Rotation / Margin After / Use Indiv Color / Color / Use Indiv Stroke / Stroke Width / Stroke Gap / Stroke Color をデフォルト値に戻します。</td></tr></tbody></table><h3 id="余白-margin-after" tabindex="-1">余白（Margin After） <a class="header-anchor" href="#余白-margin-after" aria-label="Permalink to &quot;余白（Margin After）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>パラメーター</th><th>説明</th></tr></thead><tbody><tr><td><strong>Margin After (em)</strong></td><td>その文字の後ろに追加するスペース量を em 単位で指定します。</td></tr></tbody></table><h3 id="変形パラメーター" tabindex="-1">変形パラメーター <a class="header-anchor" href="#変形パラメーター" aria-label="Permalink to &quot;変形パラメーター&quot;">​</a></h3><table tabindex="0"><thead><tr><th>パラメーター</th><th>説明</th></tr></thead><tbody><tr><td><strong>Pos</strong></td><td>文字個別の位置オフセット（X, Y）。</td></tr><tr><td><strong>Pivot</strong></td><td>文字のスケール・回転の基準点（X, Y）。</td></tr><tr><td><strong>Scale</strong></td><td>文字を均等にスケールします。</td></tr><tr><td><strong>Rotation</strong></td><td>文字の回転角度。</td></tr><tr><td><strong>Stretch</strong></td><td>文字を X / Y 方向に個別スケールします。</td></tr></tbody></table><h3 id="個別の色" tabindex="-1">個別の色 <a class="header-anchor" href="#個別の色" aria-label="Permalink to &quot;個別の色&quot;">​</a></h3><table tabindex="0"><thead><tr><th>パラメーター</th><th>説明</th></tr></thead><tbody><tr><td><strong>Use Indiv Color</strong></td><td>ON にすると、グローバルの色設定を上書きしてこの文字専用の色を使います。</td></tr><tr><td><strong>Color</strong></td><td>文字ごとの色（RGB + 透明度）。Use Indiv Color が ON のときのみ有効。</td></tr></tbody></table><h3 id="個別の輪郭線-ストローク" tabindex="-1">個別の輪郭線（ストローク） <a class="header-anchor" href="#個別の輪郭線-ストローク" aria-label="Permalink to &quot;個別の輪郭線（ストローク）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>パラメーター</th><th>説明</th><th>デフォルト</th></tr></thead><tbody><tr><td><strong>Use Indiv Stroke</strong></td><td>ON にすると、グローバルの輪郭線設定を上書きしてこの文字専用の輪郭線設定を使います。ON にすると、以下のパラメーターが表示されます。</td><td>OFF</td></tr><tr><td><strong>Stroke Width</strong></td><td>文字専用の輪郭線の太さを、フォントサイズに対する比率で指定します。</td><td><code>0.0</code></td></tr><tr><td><strong>Stroke Gap</strong></td><td>文字専用の、塗り（フィル）と輪郭線（ストローク）の間に空ける隙間の幅を、フォントサイズに対する比率で指定します。</td><td><code>0.0</code></td></tr><tr><td><strong>Stroke Color</strong></td><td>文字専用の輪郭線の色を指定します。</td><td>オフブラック (<code>#1c1c1e</code>)</td></tr></tbody></table><h3 id="個別のシャドウカラー" tabindex="-1">個別のシャドウカラー <a class="header-anchor" href="#個別のシャドウカラー" aria-label="Permalink to &quot;個別のシャドウカラー&quot;">​</a></h3><table tabindex="0"><thead><tr><th>パラメーター</th><th>説明</th><th>デフォルト</th></tr></thead><tbody><tr><td><strong>Use Indiv Shadow Color</strong></td><td>ON にすると、グローバルのシャドウカラー設定を上書きしてこの文字専用のシャドウカラー設定を使います。ON にすると、以下のパラメーターが表示されます。</td><td>OFF</td></tr><tr><td><strong>Shadow Color</strong></td><td>文字専用のシャドウの色（RGB + 不透明度）を指定します。Use Indiv Shadow Color が ON のときのみ有効。</td><td>青 (<code>#5555ff</code>・不透明)</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>個別シャドウカラーを ON にした文字は、Global Settings の <code>Draw Global Shadow</code> が <strong>OFF でも影を落とします</strong>。特定の文字にだけシャドウを付けたい場合は、グローバルシャドウを OFF のままにして、対象の文字でこの <code>Use Indiv Shadow Color</code> を ON にしてください。 なお、シャドウの距離（Distance）・角度（Angle）は Global Settings の値が共通で使われます。個別に変えられるのは色のみです。</p></div><hr><p><a id="page-part-settings"></a></p>',28)])])}const S=e(l,[["render",i]]);export{u as __pageData,S as default};
